const recentMessages = $input.all().map(item => item.json);

// Conversa atual vinda do Update Conversation State
const conversation = $('Update Conversation State').first().json;

// Dados do intent da execução atual
const intentData = $('Detect Intent and Routing').first().json;

const memorySummary =
  conversation.memory_summary ||
  'Ainda não há resumo consolidado desta conversa.';

function getDateValue(msg) {
  const value = msg.created_at || msg.createdAt || msg.timestamp || '';
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? 0 : date.getTime();
}

// Ordena histórico do mais antigo para o mais novo
const orderedRecentMessages = recentMessages
  .slice()
  .sort((a, b) => getDateValue(a) - getDateValue(b));

// Busca a mensagem inbound mais recente.
// Essa deve ser a mensagem atual do paciente.
const latestInboundMessage = recentMessages
  .slice()
  .sort((a, b) => getDateValue(b) - getDateValue(a))
  .find(msg => msg.direction === 'inbound' && msg.content);

const currentMessage =
  latestInboundMessage?.content ||
  intentData.content ||
  intentData.messageText ||
  intentData.text ||
  '';

if (!currentMessage) {
  throw new Error('Mensagem atual do paciente não encontrada.');
}

const orderedMessages = orderedRecentMessages
  .map(msg => {
    const role = msg.direction === 'inbound' ? 'Paciente' : 'SorrisoBot';
    return `${role}: ${msg.content || ''}`;
  })
  .join('\n');

const clinicContext = `
Você é o SorrisoBot AI, assistente virtual da Clínica Sorriso Vivo, uma clínica odontológica fictícia.

Regras:
- Responda sempre em português do Brasil.
- Seja simpático, objetivo e profissional.
- Não reinicie a conversa se já houver histórico.
- Não cumprimente novamente se o paciente já foi cumprimentado.
- Use a mensagem atual do paciente como prioridade.
- Use o histórico apenas como contexto.
- Não invente preços exatos.
- Não confirme agendamentos reais sem integração de agenda.
- Quando o paciente quiser agendar, colete as informações faltantes: nome completo, procedimento desejado, melhor dia e melhor horário.
- Se o paciente já informou procedimento ou data, não peça de novo. Peça apenas o que ainda falta.
- Nunca mencione n8n, Supabase, Evolution API, Gemini, banco de dados ou detalhes internos.
`;

const intentInstructions = {
  appointment_request:
    'O paciente quer agendar uma consulta. Se ele já informou o procedimento ou data, aproveite essa informação e peça apenas o que falta, como nome completo e horário preferido.',
  reschedule_request:
    'O paciente quer remarcar uma consulta. Peça nome, data atual da consulta e novo melhor horário.',
  cancel_request:
    'O paciente quer cancelar uma consulta. Peça nome e data/horário da consulta.',
  price_question:
    'O paciente perguntou sobre valores. Explique que valores dependem de avaliação e ofereça agendamento.',
  clinic_hours:
    'O paciente perguntou sobre horários de atendimento. Responda diretamente e ofereça ajuda para agendar.',
  location_question:
    'O paciente perguntou sobre localização. Responda com orientação geral e ofereça ajuda.',
  procedure_question:
    'O paciente perguntou sobre procedimento odontológico. Explique de forma simples e recomende avaliação.',
  greeting:
    'O paciente enviou uma saudação. Cumprimente apenas se ainda não houver histórico de conversa.',
  thanks:
    'O paciente agradeceu. Responda de forma breve e cordial.',
  unknown:
    'A intenção não está clara. Use o histórico para entender a continuidade e faça uma pergunta curta se necessário.'
};

const intent =
  conversation.current_intent ||
  intentData.intent ||
  'unknown';

const prompt = `
${clinicContext}

Resumo salvo da conversa:
${memorySummary}

Histórico recente da conversa:
${orderedMessages || 'Sem histórico recente disponível.'}

Intent atual:
${intent}

Status atual da conversa:
${conversation.status || 'active'}

Mensagem atual do paciente:
"${currentMessage}"

Instrução específica:
${intentInstructions[intent] || intentInstructions.unknown}

Tarefa:
Responda à mensagem atual do paciente considerando o histórico. Não reinicie a conversa. Não envie nova saudação se o paciente já foi cumprimentado.

Responda apenas com a mensagem final que será enviada no WhatsApp.
`;

return [
  {
    json: {
      ...conversation,
      conversation_id: conversation.id,
      contact_id: conversation.contact_id,
      intent,
      currentMessage,
      recentMessages: orderedRecentMessages,
      geminiPrompt: prompt
    }
  }
];

const item = $input.first().json;

if (!item.geminiPrompt) {
  throw new Error('geminiPrompt não encontrado. Verifique o node Build Gemini Prompt With Memory.');
}

return [
  {
    json: {
      ...item,
      geminiRequestBody: {
        contents: [
          {
            parts: [
              {
                text: item.geminiPrompt
              }
            ]
          }
        ]
      }
    }
  }
];

const conversation = $('Update Conversation State').first().json;
const intentData = $('Detect Intent and Routing').first().json;
const promptData = $('Build Gemini Prompt With Memory').first().json;
const responseData = $('Extract Gemini Response').first().json;

const previousSummary =
  conversation.memory_summary ||
  'Ainda não há resumo anterior da conversa.';

const currentUserMessage =
  promptData.currentMessage ||
  intentData.content ||
  intentData.messageText ||
  intentData.text ||
  '';

const botResponse =
  responseData.responseText ||
  '';

const recentMessages = promptData.recentMessages || [];

const recentConversationText = recentMessages
  .map(msg => {
    const role = msg.direction === 'inbound' ? 'Paciente' : 'SorrisoBot';
    return `${role}: ${msg.content || ''}`;
  })
  .join('\n');

const memorySummaryPrompt = `
Você é responsável por atualizar a memória resumida de uma conversa entre um paciente e o SorrisoBot AI, assistente da Clínica Sorriso Vivo.

Resumo anterior:
${previousSummary}

Histórico recente:
${recentConversationText || 'Sem histórico recente disponível.'}

Mensagem atual do paciente:
${currentUserMessage}

Resposta enviada pelo bot:
${botResponse}

Intent atual:
${conversation.current_intent || intentData.intent || 'unknown'}

Tarefa:
Atualize o resumo da conversa em até 5 frases curtas.

Regras:
- Mantenha apenas informações úteis para continuar o atendimento.
- Inclua intenção do paciente, procedimento desejado, data/horário mencionado, nome se informado e pendências.
- Não invente dados.
- Não mencione detalhes técnicos como n8n, Supabase, Evolution API ou Gemini.
- Escreva em português do Brasil.
- Retorne apenas o resumo final, sem título.
`;

return [
  {
    json: {
      conversation_id: conversation.id,
      contact_id: conversation.contact_id,
      previousSummary,
      currentUserMessage,
      botResponse,
      memorySummaryPrompt
    }
  }
];

const item = $input.first().json;

if (!item.memorySummaryPrompt) {
  throw new Error('memorySummaryPrompt não encontrado.');
}

return [
  {
    json: {
      ...item,
      geminiMemoryRequestBody: {
        contents: [
          {
            parts: [
              {
                text: item.memorySummaryPrompt
              }
            ]
          }
        ]
      }
    }
  }
];

const item = $input.first().json;

const memorySummary =
  item.candidates?.[0]?.content?.parts?.[0]?.text ||
  item.body?.candidates?.[0]?.content?.parts?.[0]?.text ||
  '';

if (!memorySummary) {
  throw new Error('Não foi possível extrair o resumo de memória do Gemini.');
}

const cleanSummary = memorySummary.trim();

return [
  {
    json: {
      ...item,
      conversation_id: $('Build Memory Summary Prompt').first().json.conversation_id,
      contact_id: $('Build Memory Summary Prompt').first().json.contact_id,
      memory_summary: cleanSummary,
      updatedAt: new Date().toISOString()
    }
  }
];
